import React from "react";
import { TopBar } from "components/Display/TopBar";
import { ScreenLayoutInner } from "./ScreenLayoutInner";
import { SideBar } from "./SideBar";

export const ScreenLayout = () => {
  return (
    <div style={{ display: "flex", flexDirection: "column", height: "100vh" }}>
      <TopBar />
      <div style={{ display: "flex", flexGrow: 1 }}>
        <div
          style={{
            position: "fixed",
            top: "64px", // Adjust based on TopBar height
            left: 0,
            width: "200px",
            height: "calc(100vh - 64px)", // Full height minus the TopBar height
            backgroundColor: "#406885",
            overflowY: "auto", // Enable scrolling if needed
          }}
        >
          <SideBar />
        </div>
        <div style={{ marginLeft: "200px", flex: "1", height: "calc(100vh - 64px)", overflowY: "auto" }}>
          <ScreenLayoutInner />
        </div>
      </div>
    </div>
  );
};
